var dataPath = Path.Combine(AppContext.BaseDirectory, "Data", "customers.csv");

// Load CSV and map "Yes"/"No" → boolean Label up front
var records = File.ReadAllLines(dataPath)
    .Skip(1)
    .Where(line => !string.IsNullOrWhiteSpace(line))
    .Select(line =>
    {
        var parts = line.Split(',');
        return new CustomerTrainingData
        {
            Age = float.Parse(parts[0], CultureInfo.InvariantCulture),
            Income = float.Parse(parts[1], CultureInfo.InvariantCulture),
            Region = parts[2].Trim(),
            PurchaseHistory = float.Parse(parts[3], CultureInfo.InvariantCulture),
            Label = parts[4].Trim().Equals("Yes", StringComparison.OrdinalIgnoreCase)
        };
    })
    .ToList();

var dataView = mlContext.Data.LoadFromEnumerable(records);
var split = mlContext.Data.TrainTestSplit(dataView, testFraction: 0.2);

var pipeline = mlContext.Transforms.Categorical.OneHotEncoding("RegionEncoded", nameof(CustomerTrainingData.Region))
    .Append(mlContext.Transforms.Concatenate("Features",
        nameof(CustomerTrainingData.Age),
        nameof(CustomerTrainingData.Income),
        "RegionEncoded",
        nameof(CustomerTrainingData.PurchaseHistory)))
    .Append(mlContext.Transforms.NormalizeMinMax("Features"))
    .Append(mlContext.BinaryClassification.Trainers.SdcaLogisticRegression(
        labelColumnName: "Label",
        featureColumnName: "Features"));

var model = pipeline.Fit(split.TrainSet);

// Evaluate on test set
var predictions = model.Transform(split.TestSet);
try
{
    var metrics = mlContext.BinaryClassification.Evaluate(predictions, labelColumnName: "Label");
    Console.WriteLine($"Model trained — AUC: {metrics.AreaUnderRocCurve:F4}, Accuracy: {metrics.Accuracy:F4}, F1: {metrics.F1Score:F4}");
}
catch (ArgumentOutOfRangeException)
{
    Console.WriteLine("Model trained — evaluation skipped (test set too small for meaningful metrics).");
}

// Save model and register pooled prediction engine
var modelPath = Path.Combine(AppContext.BaseDirectory, "ChurnModel.zip");
mlContext.Model.Save(model, dataView.Schema, modelPath);

builder.Services.AddPredictionEnginePool<CustomerTrainingData, ChurnPrediction>()
    .FromFile(modelPath);

var app = builder.Build();

app.MapGet("/", () => "Churn Predictor API — POST /predict with { age, income, region, purchaseHistory }");

app.MapPost("/predict", (PredictionEnginePool<CustomerTrainingData, ChurnPrediction> pool, CustomerRequest req) =>
